/* Default exit sequence for region main region */
static void exseq_main_region(Statechart* handle)
{
	/* Default exit sequence for region main region */
	/* Handle exit of all possible states (of Statechart.main_region) at position 0... */
	switch(handle->stateConfVector[ 0 ])
	{
		case Statechart_main_region_Vykdymas_r1_WaitSamplePeriod :
		{
			exseq_main_region_Vykdymas_r1_WaitSamplePeriod(handle);
			break;
		}
		case Statechart_main_region_Vykdymas_r1_SampleRequestedADC :
		{
			exseq_main_region_Vykdymas_r1_SampleRequestedADC(handle);
			break;
		}
		case Statechart_main_region_Vykdymas_r1_SampleReadingADC :
		{
			exseq_main_region_Vykdymas_r1_SampleReadingADC(handle);
			break;
		}
		case Statechart_main_region_Vykdymas_r1_Processing :
		{
			exseq_main_region_Vykdymas_r1_Processing(handle);
			break;
		}
		case Statechart_main_region_Start :
		{
			exseq_main_region_Start(handle);
			break;
		}
		default: 
			/* do nothing */
			break;
	}
	/* Handle exit of all possible states (of Statechart.main_region) at position 1... */
	switch(handle->stateConfVector[ 1 ])
	{
		case Statechart_main_region_Vykdymas_r2_LCD_Send :
		{
			exseq_main_region_Vykdymas_r2_LCD_Send(handle);
			break;
		}
		case Statechart_main_region_Vykdymas_r2_LCD :
		{
			exseq_main_region_Vykdymas_r2_LCD(handle);
			break;
		}
		default: 
			/* do nothing */
			break;
	}
	/* Handle exit of all possible states (of Statechart.main_region) at position 2... */
	switch(handle->stateConfVector[ 2 ])
	{
		case Statechart_main_region_Vykdymas_r3_UART :
		{
			exseq_main_region_Vykdymas_r3_UART(handle);
			break;
		}
		case Statechart_main_region_Vykdymas_r3_UART_Send :
		{
			exseq_main_region_Vykdymas_r3_UART_Send(handle);
			break;
		}
		default: 
			/* do nothing */
			break;
	}
	/* Handle exit of all possible states (of Statechart.main_region) at position 3... */
	switch(handle->stateConfVector[ 3 ])
	{
		case Statechart_main_region_Vykdymas_r4_Button :
		{
			exseq_main_region_Vykdymas_r4_Button(handle);
			break;
		}
		case Statechart_main_region_Vykdymas_r4_Check_Buttons :
		{
			exseq_main_region_Vykdymas_r4_Check_Buttons(handle);
			break;
		}
		default: 
			/* do nothing */
			break;
	}
}

