static void react_main_region__entry_Default(Statechart* handle)
{
	/* Default react sequence for initial entry  */
	enseq_main_region_Start_default(handle);
}


static sc_integer main_region_Vykdymas_react(Statechart* handle, const sc_integer transitioned_before)
{
	/* The reactions of state Vykdymas. */
 			sc_integer transitioned_after = transitioned_before;
	if (handle->doCompletion == bool_false)
	{ 
		/* Always execute local reactions. */
		transitioned_after = transitioned_before;
	} return transitioned_after;
}

static sc_integer main_region_Vykdymas_r1_WaitSamplePeriod_react(Statechart* handle, const sc_integer transitioned_before)
{
	/* The reactions of state WaitSamplePeriod. */
 			sc_integer transitioned_after = transitioned_before;
	if (handle->doCompletion == bool_false)
	{ 
		if ((transitioned_after) < (0))
		{ 
			if (handle->iface.Ev_GetSample_raised == bool_true)
			{ 
				exseq_main_region_Vykdymas_r1_WaitSamplePeriod(handle);
				enseq_main_region_Vykdymas_r1_SampleRequestedADC_default(handle);
				transitioned_after = 0;
			} 
		} 
	} return transitioned_after;
}

